var body = $json.body || $json;
var reqs = body.requirements || {};
var reqType = reqs.procurement_type || 'неопределен';
var reqStr = JSON.stringify(reqs, null, 2);
if (reqStr.length > 30000) reqStr = reqStr.substring(0, 30000);
var specStr = JSON.stringify(body.specData || {}, null, 2);
if (specStr.length > 30000) specStr = specStr.substring(0, 30000);
var ciStr = JSON.stringify(body.contractorInfo || {}, null, 2);

var p = 'Ти си експерт по структуриране на технически предложения за обществени поръчки.

';
p += 'Получаваш:
ТИП ПОРЪЧКА: ' + reqType + '

';
p += 'ИЗВЛЕЧЕНИ ИЗИСКВАНИЯ:
' + reqStr + '

';
p += 'АНАЛИЗ НА СПЕЦИФИКАЦИЯТА:
' + specStr + '

';
p += 'ИНФОРМАЦИЯ ЗА ИЗПЪЛНИТЕЛЯ:
' + ciStr + '

';

p += '## ИМПЕРАТИВНО ПРАВИЛО — СТРУКТУРА НА ДОКУМЕНТА
';
p += 'Структурата на документа ТРЯБВА да следва ТОЧНО структурата зададена от Възложителя.
';
p += '- Всяко изискване с ID от вида X.X (1.1, 1.2, 1.3, 1.4 и т.н.) = ГЛАВНА СЕКЦИЯ на документа.
';
p += '- Заглавието на секцията = ТОЧНО заглавието от изискването, без промяна и без преименуване.
';
p += '- Редът на секциите = ТОЧНО редът от изискванията.
';
p += '- Подсекциите (subsections) ги определяш ти, но ТРЯБВА да обхванат ВСИЧКО поискано в full_text на изискването.
';
p += '- Sub-requirements от изискването ЗАДЪЛЖИТЕЛНО стават подсекции или ключова част от content_guidance.
';
p += '- НЕ ДОБАВЯЙ секции, които НЕ СА поискани от възложителя!
';
p += '- НЕ ПРЕПОДРЕЖДАЙ и НЕ ПРЕИМЕНУВАЙ секциите!
';
p += '- Изисквания от общ характер (срок за изпълнение, гаранционни срокове и т.н.) НЕ стават отделни секции — информацията от тях се интегрира в съответните секции.

';

p += '## ФОРМАТ НА МЕРКИ
';
p += 'Навсякъде, където възложителят изисква представяне на МЯРКА (мерки), всяка мярка ЗАДЪЛЖИТЕЛНО получава СВОЯ ОТДЕЛНА подсекция.
';
p += 'В content_guidance на подсекцията за мярка ЗАДЪЛЖИТЕЛНО напиши, че мярката трябва да съдържа:
';
p += '1. Наименование на мярката
';
p += '2. Същност на мярката
';
p += '3. Конкретни дейности, които се предвиждат за изпълнението й
';
p += '4. Времеви план за прилагане на дейностите по мярката
';
p += '5. Конкретен експерт, ангажиран с прякото изпълнение + конкретни задължения (ако повече от 1 — кой коя дейност изпълнява)
';
p += '6. Контролни дейности и мониторинг: честота на прегледи, действия при констатирани отклонения, лица отговорни за контрола
';
p += '7. Дефиниране на очаквания и целен ефект от прилагането на мярката
';
p += 'ЗАБРАНЕНО е елементи от различни мерки да се обединяват! Всяка мярка = отделна самостоятелна подсекция.

';

p += '## ПРАВИЛА ЗА ПОДСЕКЦИИ
';
p += '1. Всяка подсекция е МАКСИМУМ 5 страници (~1875 думи)
';
p += '2. Ако тема изисква повече от 5 стр. — раздели на 2+ подсекции
';
p += '3. Всяка подсекция ще бъде написана от ОТДЕЛЕН AI агент, затова указанията в content_guidance трябва да са САМОДОСТАТЪЧНИ
';
p += '4. В content_guidance включи: какво точно да пише, кои конкретни данни от спецификацията да ползва, кои таблици да направи
';
p += '5. Линейният график ЗАДЪЛЖИТЕЛНО е ОТДЕЛНА подсекция с указание за таблична форма (Дейност | Седмица/Период | Ресурси | Отговорник)
';
p += '6. Реалистичен общ обем: 20-60 стр. в зависимост от сложността на поръчката
';
p += '7. Когато full_text на изискването казва "следва да се посочат" или "следва да бъдат обхванати" — включи в content_guidance с директна инструкция

';

p += '## ФОРМАТ
Върни САМО валиден JSON (БЕЗ markdown блокове):
';
p += '{
  "document_title": "ПРЕДЛОЖЕНИЕ ЗА ИЗПЪЛНЕНИЕ на [точно наименование на поръчката]",
';
p += '  "procurement_type": "' + reqType + '",
';
p += '  "total_estimated_pages": 40,
';
p += '  "sections": [
    {
';
p += '      "id": "1.1",
      "title": "ТОЧНО заглавието от изискването",
';
p += '      "requirement_id": "1.1",
';
p += '      "subsections": [
        {
';
p += '          "id": "1.1.1",
          "title": "Подзаглавие",
';
p += '          "estimated_pages": 4,
';
p += '          "content_guidance": ["Конкретно какво да се напише..."],
';
p += '          "spec_data_to_use": ["key_quantities"],
';
p += '          "tables_needed": [{"title": "Заглавие", "columns": ["Кол1", "Кол2"]}]
';
p += '        }
      ]
    }
  ],
';
p += '  "appendices": []
}

';
p += 'ПОМНИ:
';
p += '- Секциите = requirement IDs от изискванията. НЕ измисляй собствена структура!
';
p += '- Всяка мярка = ОТДЕЛНА самостоятелна подсекция с ПЪЛЕН формат в content_guidance!
';
p += '- Заглавията = ТОЧНО от изискванията!
';
p += 'САМО JSON, без друг текст.';

return [{ json: { prompt: p } }];

var raw = ($json.text || $json.response || '').trim();
var result = null;

// Sanitize Unicode smart quotes that break JSON parsing
function sanitize(s) {
  return s.replace(/[\u201C\u201D\u201E\u201F\u00AB\u00BB\u2018\u2019]/g, "'");
}

function tryParse(s) {
  try { return JSON.parse(s); } catch(e) { return null; }
}

function extractJson(s) {
  var m = s.match(/```(?:json)?\s*([\s\S]*?)```/);
  var c = m ? m[1].trim() : s;
  var start = c.indexOf('{');
  var end = c.lastIndexOf('}');
  if (start === -1 || end === -1) return s;
  return c.substring(start, end + 1);
}

function fixCommon(s) {
  // Remove trailing commas before ] or }
  s = s.replace(/,\s*([\]\}])/g, '$1');
  return s;
}

// Character-by-character parser for unescaped quotes inside JSON strings
function fixQuotes(s) {
  var out = '';
  var inStr = false;
  var escaped = false;
  for (var i = 0; i < s.length; i++) {
    var ch = s[i];
    if (escaped) { out += ch; escaped = false; continue; }
    if (ch === '\\') { out += ch; escaped = true; continue; }
    if (ch === '"') {
      if (!inStr) {
        inStr = true;
        out += ch;
      } else {
        var rest = s.substring(i + 1).trimStart();
        var next = rest.length > 0 ? rest[0] : '';
        if (next === ':' || next === ',' || next === '}' || next === ']' || rest.length === 0) {
          inStr = false;
          out += ch;
        } else {
          out += '\\"';
        }
      }
    } else {
      out += ch;
    }
  }
  return out;
}

// Step 0: sanitize smart quotes
raw = sanitize(raw);

// Strategy 1: direct parse
result = tryParse(raw);

// Strategy 2: extract from markdown + fix trailing commas
if (!result) {
  var extracted = fixCommon(extractJson(raw));
  result = tryParse(extracted);
}

// Strategy 3: fixQuotes fallback
if (!result) {
  var extracted2 = fixCommon(extractJson(raw));
  result = tryParse(fixQuotes(extracted2));
}

// Fallback with error marker
if (!result) {
  result = { document_title: 'Parse error', sections: [], _raw: raw.substring(0, 5000), _parse_error: true };
}

return [{ json: { documentPlan: result } }];
